{
  "name": "Goblin Grafix",
  "description": "A retro-futuristic static site for a creator brand featuring a 3D masthead and social links."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SocialLink {
  name: string;
  url: string;
  icon: React.FC<React.SVGProps<SVGSVGElement>>;
}

export interface NewsletterFormProps {
  onSubmit: (email: string) => void;
}

import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Center, Text3D, Environment } from '@react-three/drei';
import { EffectComposer, ChromaticAberration, Bloom } from '@react-three/postprocessing';
import * as THREE from 'three';

// NOTE: To change the font to actual Courier New, you need to generate a .json typeface file
// and point the `font` prop to it. The URL below is a placeholder standard font.
// You can convert fonts here: https://gero3.github.io/facetype.js/
const FONT_URL = 'https://threejs.org/examples/fonts/helvetiker_bold.typeface.json';

const FloatingText = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame(({ clock }) => {
    if (groupRef.current) {
      // Gentle wobbling effect
      const t = clock.getElapsedTime();
      groupRef.current.rotation.y = Math.sin(t * 0.5) * 0.15;
      groupRef.current.rotation.x = Math.cos(t * 0.3) * 0.05;
      groupRef.current.position.y = Math.sin(t * 0.8) * 0.2;
    }
  });

  // Settings for the text geometry
  const textOptions = {
    font: FONT_URL,
    size: 0.8,
    height: 0.2, // Thickness of the 3D text
    curveSegments: 12,
    bevelEnabled: true,
    bevelThickness: 0.02,
    bevelSize: 0.02,
    bevelOffset: 0,
    bevelSegments: 5,
  };

  return (
    <group ref={groupRef}>
      <Center>
        <group>
          {/* Top Word: GOBLIN */}
          <Text3D position={[0, 0.55, 0]} {...textOptions}>
            GOBLIN
            <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.8} />
          </Text3D>

          {/* Bottom Word: GRAFIX */}
          <Text3D position={[0, -0.55, 0]} {...textOptions}>
            GRAFIX
            <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.8} />
          </Text3D>

          {/* 
             PLACEHOLDER FOR YOUR FUTURE MODEL:
             When you have your own .glb/.gltf file:
             1. Import { useGLTF } from '@react-three/drei'
             2. const { scene } = useGLTF('/path/to/model.glb')
             3. Replace the <Text3D> components with <primitive object={scene} />
          */}
        </group>
      </Center>
    </group>
  );
};

export const Masthead3D: React.FC = () => {
  return (
    <div className="w-full h-[400px] border-b-2 border-zinc-800 bg-black relative overflow-hidden">
      {/* 
         Canvas is the entry point for the 3D Scene.
         dpr ensures crisp rendering on high-res screens.
      */}
      <Canvas dpr={[1, 2]} camera={{ position: [0, 0, 6], fov: 45 }}>
        {/* Lights */}
        <ambientLight intensity={0.5} />
        <directionalLight position={[10, 10, 5]} intensity={2} />
        <spotLight position={[-10, -10, 5]} intensity={1} color="purple" />

        {/* The 3D Content */}
        <FloatingText />

        {/* Post Processing Effects */}
        <EffectComposer disableNormalPass>
            {/* Chromatic Aberration gives that "glitchy" lens look */}
            <ChromaticAberration offset={new THREE.Vector2(0.004, 0.004)} radialModulation={false} modulationOffset={0} />
            <Bloom luminanceThreshold={1} intensity={0.5} levels={9} mipmapBlur />
        </EffectComposer>

        {/* Environment reflection mapping */}
        <Environment preset="city" />
      </Canvas>

      {/* Overlay text for accessibility or fallback if JS fails (though React requires JS) */}
      <div className="absolute top-2 left-2 text-xs text-zinc-700 pointer-events-none select-none">
        [interactive_masthead_v1.0]
      </div>
    </div>
  );
};

import React, { useState } from 'react';

export const NewsletterForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<'idle' | 'success' | 'submitting'>('idle');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) return;

    setStatus('submitting');
    // Simulate API call
    setTimeout(() => {
      console.log(`Signed up: ${email}`);
      setStatus('success');
      setEmail('');
    }, 1000);
  };

  return (
    <div className="w-full max-w-md mx-auto mt-12 mb-8 p-4 border-2 border-dashed border-zinc-800 text-center">
      <h3 className="text-xl font-bold mb-4 uppercase tracking-tighter">
        Join the Horde (Newsletter)
      </h3>

      {status === 'success' ? (
        <div className="p-4 bg-zinc-900 text-green-500 font-bold border border-green-900">
          > EMAIL REGISTERED. WELCOME.
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <label htmlFor="email" className="sr-only">Email Address</label>
            <input
              type="email"
              id="email"
              placeholder="ENTER_EMAIL_ADDRESS"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-black border border-zinc-600 p-3 text-white placeholder-zinc-600 focus:outline-none focus:border-white font-mono"
              required
            />
            <button
              type="submit"
              disabled={status === 'submitting'}
              className="w-full bg-zinc-900 border border-zinc-600 p-3 text-white uppercase hover:bg-white hover:text-black transition-colors font-bold disabled:opacity-50"
            >
              {status === 'submitting' ? 'PROCESSING...' : 'SUBSCRIBE'}
            </button>
        </form>
      )}

      <p className="text-xs text-zinc-600 mt-4">
        No spam. Only updates on new creations.
      </p>
    </div>
  );
};

