import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Center, Text3D, Environment } from '@react-three/drei';
import { EffectComposer, ChromaticAberration, Bloom } from '@react-three/postprocessing';
import * as THREE from 'three';

// Fix for missing types in JSX.IntrinsicElements for R3F components
declare global {
  namespace JSX {
    interface IntrinsicElements {
      group: any;
      meshStandardMaterial: any;
      ambientLight: any;
      directionalLight: any;
      spotLight: any;
    }
  }
}

// NOTE: To change the font to actual Courier New, you need to generate a .json typeface file
// and point the `font` prop to it. The URL below is a placeholder standard font.
// You can convert fonts here: https://gero3.github.io/facetype.js/
const FONT_URL = 'https://threejs.org/examples/fonts/helvetiker_bold.typeface.json';

const InteractiveChromaticAberration = () => {
  const ref = useRef<any>(null);

  useFrame((state) => {
    if (ref.current) {
      // Mouse position (-1 to 1)
      const { x, y } = state.pointer;

      // Calculate target offset based on mouse intensity
      // Base offset + mouse offset
      // We want a glitchier effect at the edges
      const targetX = x * 0.01;
      const targetY = y * 0.01;

      // Smoothly interpolate the offset values
      ref.current.offset.x = THREE.MathUtils.lerp(ref.current.offset.x, targetX, 0.1);
      ref.current.offset.y = THREE.MathUtils.lerp(ref.current.offset.y, targetY, 0.1);
    }
  });

  return (
    <ChromaticAberration
      ref={ref}
      // Initial value, though it will be overwritten by the lerp almost immediately
      offset={[0.002, 0.002]} 
      radialModulation={false}
      modulationOffset={0}
    />
  );
};

const FloatingText = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (groupRef.current) {
      const { clock, pointer } = state;
      const t = clock.getElapsedTime();

      // Base wobble (time based)
      const wobbleX = Math.cos(t * 0.3) * 0.05;
      const wobbleY = Math.sin(t * 0.5) * 0.15;
      const floatY = Math.sin(t * 0.8) * 0.2;

      // Mouse influence
      // pointer.x/y are normalized coordinates (-1 to 1)
      const mouseRotateY = pointer.x * 0.5; // Horizontal mouse moves rotates around Y
      const mouseRotateX = -pointer.y * 0.5; // Vertical mouse moves rotates around X

      // Target rotations
      const targetRotX = wobbleX + mouseRotateX;
      const targetRotY = wobbleY + mouseRotateY;

      // Smoothly interpolate current rotation to target
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRotX, 0.1);
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRotY, 0.1);

      // Position update (parallax)
      const targetPosX = pointer.x * 0.5;
      const targetPosY = floatY + (pointer.y * 0.2);

      groupRef.current.position.x = THREE.MathUtils.lerp(groupRef.current.position.x, targetPosX, 0.1);
      groupRef.current.position.y = THREE.MathUtils.lerp(groupRef.current.position.y, targetPosY, 0.1);
    }
  });

  // Settings for the text geometry
  const textOptions = {
    font: FONT_URL,
    size: 0.8,
    height: 0.2, // Thickness of the 3D text
    curveSegments: 12,
    bevelEnabled: true,
    bevelThickness: 0.02,
    bevelSize: 0.02,
    bevelOffset: 0,
    bevelSegments: 5,
  };

  return (
    <group ref={groupRef}>
      <Center>
        <group>
          {/* Top Word: GOBLIN */}
          <Text3D position={[0, 0.55, 0]} {...textOptions}>
            GOBLIN
            <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.8} />
          </Text3D>

          {/* Bottom Word: GRAFIX */}
          <Text3D position={[0, -0.55, 0]} {...textOptions}>
            GRAFIX
            <meshStandardMaterial color="#ffffff" roughness={0.3} metalness={0.8} />
          </Text3D>

          {/* 
             PLACEHOLDER FOR YOUR FUTURE MODEL:
             When you have your own .glb/.gltf file:
             1. Import { useGLTF } from '@react-three/drei'
             2. const { scene } = useGLTF('/path/to/model.glb')
             3. Replace the <Text3D> components with <primitive object={scene} />
          */}
        </group>
      </Center>
    </group>
  );
};

export const Masthead3D: React.FC = () => {
  return (
    <div className="w-full h-[400px] border-b-2 border-zinc-800 bg-black relative overflow-hidden">
      {/* 
         Canvas is the entry point for the 3D Scene.
         dpr ensures crisp rendering on high-res screens.
      */}
      <Canvas dpr={[1, 2]} camera={{ position: [0, 0, 6], fov: 45 }}>
        {/* Lights */}
        <ambientLight intensity={0.5} />
        <directionalLight position={[10, 10, 5]} intensity={2} />
        <spotLight position={[-10, -10, 5]} intensity={1} color="purple" />

        {/* The 3D Content */}
        <FloatingText />

        {/* Post Processing Effects */}
        <EffectComposer disableNormalPass>
            {/* Chromatic Aberration gives that "glitchy" lens look */}
            <InteractiveChromaticAberration />
            <Bloom luminanceThreshold={1} intensity={0.5} levels={9} mipmapBlur />
        </EffectComposer>

        {/* Environment reflection mapping */}
        <Environment preset="city" />
      </Canvas>

      {/* Overlay text for accessibility or fallback if JS fails (though React requires JS) */}
      <div className="absolute top-2 left-2 text-xs text-zinc-700 pointer-events-none select-none">
        [interactive_masthead_v1.0]
      </div>
    </div>
  );
};

