const FONT_URL = 'https://threejs.org/examples/fonts/helvetiker_bold.typeface.json';

const DynamicChromaticAberration = () => {
  const ref = useRef<any>(null);

  useFrame((state) => {
    if (ref.current) {
      const t = state.clock.getElapsedTime();

      // Vary between 0.002 and 0.005
      // Center point: 0.0035
      // Max deviation: 0.0015
      // We use two sine waves to make the "randomness" feel less repetitive
      const fluctuation = Math.sin(t * 3) * 0.001 + Math.cos(t * 4.5) * 0.0005;
      const intensity = 0.0035 + fluctuation;

      ref.current.offset.set(intensity, intensity);
    }
  });

