  namespace JSX {
    interface IntrinsicElements {
      group: any;
      meshStandardMaterial: any;
      ambientLight: any;
      directionalLight: any;
      spotLight: any;
    }
  }
}

// Using Droid Sans Mono for the typewriter look
const FONT_URL = 'https://threejs.org/examples/fonts/droid/droid_sans_mono_regular.typeface.json';

const DynamicChromaticAberration = () => {
  const ref = useRef<any>(null);

  useFrame((state) => {
    if (ref.current) {
      const elapsedTime = state.clock.getElapsedTime();

      // Smooth sine-wave based wobble calculation
      const x = 0.003 + Math.sin(elapsedTime * 5) * 0.0002;
      const y = 0.003 + Math.sin(elapsedTime * 5 + 3) * 0.0002;

      // Create the vector as requested
      const CAwobble = new THREE.Vector2(x, y);

      // Apply the vector to the offset
      ref.current.offset = CAwobble;
    }
  });

  return (
    <ChromaticAberration
      ref={ref}
      offset={[0.002, 0.002]}
      radialModulation={false}
      modulationOffset={0}
    />
  );
};

const FloatingText = () => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (groupRef.current) {
      const { clock, pointer } = state;
      const t = clock.getElapsedTime();

      // Mouse influence (pointer.x/y is -1 to 1)
      const targetRotY = pointer.x * 0.3; // Look left/right
      const targetRotX = -pointer.y * 0.2; // Look up/down

      // Base wobble
      const wobbleY = Math.sin(t * 0.5) * 0.1;
      const wobbleX = Math.cos(t * 0.3) * 0.05;

      // Smoothly interpolate current rotation to target (mouse + wobble)
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, targetRotY + wobbleY, 0.1);
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, targetRotX + wobbleX, 0.1);

      // Floating motion
      groupRef.current.position.y = Math.sin(t * 0.8) * 0.15;
    }
  });

  // Settings for the text geometry
  // Increased bevelThickness and bevelSize to simulate a BOLD font weight
  const textOptions = {
    font: FONT_URL,
